// hooks/useWeather.js
import { useState, useEffect, useCallback } from 'react';
import { Alert, Platform } from 'react-native';
import Geolocation from '@react-native-community/geolocation';
import AsyncStorage from '@react-native-async-storage/async-storage';
import axios from 'axios';

const API_KEY = 'VOTRE_CLE_API';
const BASE_URL = 'https://api.openweathermap.org/data/2.5';
const CACHE_KEY = '@last_city';

export const useWeather = () => {
  const [weather, setWeather] = useState(null);
  const [forecast, setForecast] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [currentCity, setCurrentCity] = useState('');

  // Conversion Kelvin vers Celsius
  const kelvinToCelsius = (kelvin) => (kelvin - 273.15).toFixed(1);

  // Appel API météo par coordonnées
  const fetchWeatherByCoords = useCallback(async (lat, lon) => {
    setLoading(true);
    setError(null);
    try {
      const [weatherRes, forecastRes] = await Promise.all([
        axios.get(`${BASE_URL}/weather`, {
          params: { lat, lon, appid: API_KEY, units: 'metric' }
        }),
        axios.get(`${BASE_URL}/forecast`, {
          params: { lat, lon, appid: API_KEY, units: 'metric', cnt: 40 }
        })
      ]);

      setWeather({
        temp: weatherRes.data.main.temp,
        feelsLike: weatherRes.data.main.feels_like,
        humidity: weatherRes.data.main.humidity,
        windSpeed: weatherRes.data.wind.speed,
        description: weatherRes.data.weather[0].description,
        icon: weatherRes.data.weather[0].icon,
        city: weatherRes.data.name,
        country: weatherRes.data.sys.country
      });

      setCurrentCity(weatherRes.data.name);
      await AsyncStorage.setItem(CACHE_KEY, weatherRes.data.name);

      // Traitement des prévisions (1 jour = 8 intervalles de 3h)
      const dailyForecast = forecastRes.data.list.filter((_, index) => index % 8 === 0);
      setForecast(dailyForecast.map(item => ({
        date: item.dt_txt,
        temp: item.main.temp,
        tempMin: item.main.temp_min,
        tempMax: item.main.temp_max,
        humidity: item.main.humidity,
        description: item.weather[0].description,
        icon: item.weather[0].icon
      })));
    } catch (err) {
      setError(err.response?.data?.message || 'Erreur lors du chargement de la météo');
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  // Appel API par nom de ville
  const fetchWeatherByCity = useCallback(async (city) => {
    setLoading(true);
    setError(null);
    try {
      const [weatherRes, forecastRes] = await Promise.all([
        axios.get(`${BASE_URL}/weather`, {
          params: { q: city, appid: API_KEY, units: 'metric' }
        }),
        axios.get(`${BASE_URL}/forecast`, {
          params: { q: city, appid: API_KEY, units: 'metric', cnt: 40 }
        })
      ]);

      setWeather({
        temp: weatherRes.data.main.temp,
        feelsLike: weatherRes.data.main.feels_like,
        humidity: weatherRes.data.main.humidity,
        windSpeed: weatherRes.data.wind.speed,
        description: weatherRes.data.weather[0].description,
        icon: weatherRes.data.weather[0].icon,
        city: weatherRes.data.name,
        country: weatherRes.data.sys.country
      });

      setCurrentCity(weatherRes.data.name);
      await AsyncStorage.setItem(CACHE_KEY, weatherRes.data.name);

      const dailyForecast = forecastRes.data.list.filter((_, index) => index % 8 === 0);
      setForecast(dailyForecast.map(item => ({
        date: item.dt_txt,
        temp: item.main.temp,
        tempMin: item.main.temp_min,
        tempMax: item.main.temp_max,
        humidity: item.main.humidity,
        description: item.weather[0].description,
        icon: item.weather[0].icon
      })));
    } catch (err) {
      if (err.response?.status === 404) {
        setError(`Ville "${city}" non trouvée. Vérifiez l'orthographe.`);
      } else {
        setError(err.response?.data?.message || 'Erreur lors du chargement de la météo');
      }
    } finally {
      setLoading(false);
    }
  }, []);

  // Obtenir la géolocalisation
  const getCurrentLocation = useCallback(() => {
    setLoading(true);
    Geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        fetchWeatherByCoords(latitude, longitude);
      },
      (err) => {
        console.warn('Erreur géolocalisation:', err);
        // Fallback : charger la dernière ville en cache
        loadLastCity();
      },
      { enableHighAccuracy: true, timeout: 15000, maximumAge: 10000 }
    );
  }, [fetchWeatherByCoords]);

  // Charger la dernière ville depuis le cache
  const loadLastCity = useCallback(async () => {
    try {
      const lastCity = await AsyncStorage.getItem(CACHE_KEY);
      if (lastCity) {
        await fetchWeatherByCity(lastCity);
      } else {
        setError('Impossible d\'obtenir votre position. Veuillez rechercher une ville.');
        setLoading(false);
      }
    } catch (err) {
      setError('Erreur de chargement du cache');
      setLoading(false);
    }
  }, [fetchWeatherByCity]);

  // Initialisation au montage
  useEffect(() => {
    getCurrentLocation();
  }, []);

  return {
    weather,
    forecast,
    loading,
    error,
    currentCity,
    fetchWeatherByCity,
    refresh: getCurrentLocation,
    kelvinToCelsius
  };
};
