// hooks/__tests__/useWeather.test.js
import { renderHook, act, waitFor } from '@testing-library/react-native';
import { useWeather } from '../useWeather';
import Geolocation from '@react-native-community/geolocation';
import AsyncStorage from '@react-native-async-storage/async-storage';
import axios from 'axios';

// Mocks
jest.mock('@react-native-community/geolocation', () => ({
  getCurrentPosition: jest.fn(),
}));

jest.mock('@react-native-async-storage/async-storage', () => ({
  getItem: jest.fn(),
  setItem: jest.fn(),
}));

jest.mock('axios');
const mockedAxios = axios;

describe('useWeather', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  test('devrait charger la météo à partir de la géolocalisation avec succès', async () => {
    // Arrange
    const mockPosition = {
      coords: { latitude: 48.8566, longitude: 2.3522 }
    };
    Geolocation.getCurrentPosition.mockImplementation((success) => success(mockPosition));

    const mockWeatherResponse = {
      data: {
        main: { temp: 18.5, feels_like: 17.2, humidity: 65 },
        wind: { speed: 3.2 },
        weather: [{ description: 'ciel dégagé', icon: '01d' }],
        name: 'Paris',
        sys: { country: 'FR' }
      }
    };

    const mockForecastResponse = {
      data: {
        list: [
          { dt_txt: '2024-01-15 12:00:00', main: { temp: 18, temp_min: 12, temp_max: 20 }, weather: [{ icon: '01d' }] },
          { dt_txt: '2024-01-16 12:00:00', main: { temp: 17, temp_min: 11, temp_max: 19 }, weather: [{ icon: '02d' }] }
        ]
      }
    };

    mockedAxios.get.mockImplementation((url) => {
      if (url.includes('/weather')) return Promise.resolve(mockWeatherResponse);
      if (url.includes('/forecast')) return Promise.resolve(mockForecastResponse);
      return Promise.reject();
    });

    // Act
    const { result } = renderHook(() => useWeather());

    // Assert - état de chargement initial
    expect(result.current.loading).toBe(true);

    // Attend la fin du chargement
    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });

    // Vérifie les données
    expect(result.current.weather).toBeDefined();
    expect(result.current.weather.city).toBe('Paris');
    expect(result.current.weather.temp).toBe(18.5);
    expect(result.current.forecast.length).toBeGreaterThan(0);
    expect(AsyncStorage.setItem).toHaveBeenCalledWith('@last_city', 'Paris');
  });

  test('devrait utiliser le cache si la géolocalisation échoue', async () => {
    // Arrange
    Geolocation.getCurrentPosition.mockImplementation((_, error) => 
      error({ code: 1, message: 'Permission denied' })
    );
    AsyncStorage.getItem.mockResolvedValue('Lyon');

    const mockWeatherResponse = {
      data: { main: { temp: 20 }, name: 'Lyon', sys: { country: 'FR' }, weather: [{}], wind: { speed: 2 } }
    };
    mockedAxios.get.mockResolvedValue(mockWeatherResponse);

    // Act
    const { result } = renderHook(() => useWeather());

    // Assert
    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });
    expect(result.current.weather.city).toBe('Lyon');
    expect(AsyncStorage.getItem).toHaveBeenCalledWith('@last_city');
  });

  test('devrait gérer les erreurs API (ville non trouvée)', async () => {
    // Arrange
    Geolocation.getCurrentPosition.mockImplementation((success) => 
      success({ coords: { latitude: 0, longitude: 0 } })
    );
    mockedAxios.get.mockRejectedValue({
      response: { status: 404, data: { message: 'city not found' } }
    });

    // Act
    const { result } = renderHook(() => useWeather());

    // Assert
    await waitFor(() => {
      expect(result.current.loading).toBe(false);
    });
    expect(result.current.error).toContain('non trouvée');
  });

  test('fetchWeatherByCity devrait permettre la recherche manuelle', async () => {
    // Arrange
    const mockWeatherResponse = {
      data: { main: { temp: 25 }, name: 'Marseille', sys: { country: 'FR' }, weather: [{}], wind: { speed: 4 } }
    };
    mockedAxios.get.mockResolvedValue(mockWeatherResponse);

    const { result } = renderHook(() => useWeather());

    // Act
    await act(async () => {
      await result.current.fetchWeatherByCity('Marseille');
    });

    // Assert
    expect(result.current.weather.city).toBe('Marseille');
    expect(AsyncStorage.setItem).toHaveBeenCalledWith('@last_city', 'Marseille');
  });
});
